def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(1, 5):
                for b in range(a, 10):
                    val = ((ratio - 7) ** a) / (b + 0.5)
                    priority += val * np.sin(ratio * b / (a + 1)) * np.exp(-val)
            priority += np.tanh(ratio - 7) * 25
            for c in range(1, 6):
                priority += np.cos(c * ratio * i) * ((ratio - 7) / c) ** 2
        elif 5 < ratio <= 7:
            acc = 0
            for d in range(1, 8):
                for e in range(1, d + 4):
                    acc += ((ratio - 5) ** 3) / (d * e + 1) * np.cos(ratio * e / (d + 0.5))
            priority = acc * np.tanh(ratio) * 12
            if bin_cap < item * 1.05:
                priority += np.sqrt(item * ratio / (bin_cap + 0.3)) * 6
            else:
                priority -= np.exp(-ratio) * 8
        elif 3 < ratio <= 5:
            s = 0
            for f in range(1, 15):
                s += ((ratio - 3) ** f) / (f ** 2 + 1) * np.sin(f * ratio * 1.5)
            priority = s * np.log1p(ratio) * 8 - np.tanh(2 * (5 - ratio)) * 5
            for g in range(1, 4):
                priority += np.cos(g * i * ratio) * (ratio / g)
        elif 1.2 <= ratio <= 3:
            total = 0
            for h in range(1, 20):
                total += ((ratio - 1.2) ** h) / (h * 2.5) * np.cos(h * ratio * 2)
            penalty = 0
            for j in range(1, 8):
                if (i + j) % 5 == 0:
                    penalty += np.sin(j * bin_cap * 0.7) * j
                else:
                    penalty -= np.cos(j * item * 0.9) / (j + 1)
            priority = total + penalty
            priority += np.exp(-ratio) * 4
        elif 0.6 <= ratio < 1.2:
            s = 0
            for k in range(1, 12):
                power = (1.2 - ratio) ** k
                s += power / (k + 0.3) * np.tanh(k * ratio)
            if bin_cap > item * 1.3:
                penalty = np.log1p(bin_cap - item) * 3
            else:
                penalty = np.exp(-5 * ratio) * 7
            priority = s + penalty
            for l in range(1, 6):
                if (i * l) % 3 == 0:
                    priority += np.sin(l * ratio * i) / (l + 0.5)
                else:
                    priority -= np.cos(l * ratio * item) * 1.3
        elif 0.25 <= ratio < 0.6:
            s = 0
            for m in range(1, 18):
                s += ((0.6 - ratio) ** m) / (m * 5) * np.sin(m * ratio * 3)
            priority = s * np.log1p(bin_cap + 2)
            if int(item * 2) % 3 == 0:
                priority *= 1.8
            else:
                priority /= 2.2
            if bin_cap < item * 0.4:
                priority += np.sqrt(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 2) * 2.7
        elif 0.05 <= ratio < 0.25:
            s = 0
            for n in range(1, 14):
                s += ((0.25 - ratio) ** n) / (n * 7) * np.cos(n * ratio * 4)
            priority = s + 3 / (bin_cap + 2)
            if (i + int(item * 2.3)) % 7 == 0:
                priority *= 2.9
            else:
                priority /= 2.9
            if bin_cap < item * 0.15:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 3.5
            for o in range(1, 9):
                priority += ((0.25 - ratio) ** o) / (o * 8) * np.sin(item * o * 1.05)
        else:
            s = 0
            for p in range(1, 11):
                base = ((0.05 - ratio) ** p) / (p * 9)
                s += base * np.cos(p * item * 1.1)
            priority = s + 4 / (bin_cap + 5)
            if int(item * 0.6) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap * 1.5) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 4.2
            for q in range(1, 10):
                priority += ((0.05 - ratio) ** q) / (q * 10) * np.sin(item * q * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
            for r in range(1, 4):
                priority += np.sin(r * ratio * i * 1.5) * (0.5 - ratio) * 2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
            for s in range(1, 5):
                priority -= np.cos(s * ratio * (i + 2)) * 0.5
        for t in range(1, 5):
            if (i + t * 2) % 4 == 0:
                priority += np.sin(ratio * (i + t)) * 0.35 * t
            else:
                priority -= np.cos(ratio * (i + t)) * 0.35 * t
        if i % 5 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
